package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.*

/**
 * Tests for specific bug fixes.
 * See https://gist.github.com/ilma4/a5ad5b5c284969e24f4e2149a2f8b273
 */
class BugFixesTest {

    /**
     * Test that DateTimePeriod.parse and DatePeriod.parse reject "P" without any components.
     * ISO 8601 requires at least one component after "P".
     */
    @Test
    fun testDateTimePeriodParseRejectsBareP() {
        // "P" without any components should be rejected
        assertInvalidFormat { DateTimePeriod.parse("P") }
        assertInvalidFormat { DatePeriod.parse("P") }

        // "PT" without any time components should also be rejected
        assertInvalidFormat { DateTimePeriod.parse("PT") }
        assertInvalidFormat { DatePeriod.parse("PT") }

        // "-P" and "+P" without components should also be rejected
        assertInvalidFormat { DateTimePeriod.parse("-P") }
        assertInvalidFormat { DateTimePeriod.parse("+P") }

        // Valid periods should still work
        assertEquals(DateTimePeriod(days = 0), DateTimePeriod.parse("P0D"))
        assertEquals(DateTimePeriod(hours = 0), DateTimePeriod.parse("PT0H"))
        assertEquals(DateTimePeriod(years = 1), DateTimePeriod.parse("P1Y"))
        assertEquals(DateTimePeriod(hours = 1), DateTimePeriod.parse("PT1H"))
    }

    /**
     * Test that LocalDate.parse works with strings that have many leading zeroes in the year.
     * This behavior should be consistent between LocalDate.parse(s) and LocalDate.Formats.ISO.parse(s).
     */
    @Test
    fun testLocalDateParseWithLeadingZeroes() {
        // Year with many leading zeroes should be parsed correctly
        val date = LocalDate.parse("+00000000000002022-07-16")
        assertEquals(2022, date.year)
        assertEquals(7, date.monthNumber)
        assertEquals(16, date.dayOfMonth)

        // Verify consistency: LocalDate.parse should behave the same as Formats.ISO.parse
        val dateFromFormat = LocalDate.Formats.ISO.parse("+00000000000002022-07-16")
        assertEquals(date, dateFromFormat)

        // Also test negative years with leading zeroes
        val negativeDate = LocalDate.parse("-00000000000000001-01-01")
        assertEquals(-1, negativeDate.year)
        assertEquals(1, negativeDate.monthNumber)
        assertEquals(1, negativeDate.dayOfMonth)

        // Test zero year with leading zeroes
        val zeroYearDate = LocalDate.parse("+00000000000000000-06-15")
        assertEquals(0, zeroYearDate.year)
        assertEquals(6, zeroYearDate.monthNumber)
        assertEquals(15, zeroYearDate.dayOfMonth)
    }

    /**
     * Test that LocalDateTime.parse works with strings that have many leading zeroes in the year.
     * This behavior should be consistent between LocalDateTime.parse(s) and LocalDateTime.Formats.ISO.parse(s).
     */
    @Test
    fun testLocalDateTimeParseWithLeadingZeroes() {
        // Year with many leading zeroes should be parsed correctly
        val datetime = LocalDateTime.parse("+00000000000002022-07-16T12:30:45")
        assertEquals(2022, datetime.year)
        assertEquals(7, datetime.monthNumber)
        assertEquals(16, datetime.dayOfMonth)
        assertEquals(12, datetime.hour)
        assertEquals(30, datetime.minute)
        assertEquals(45, datetime.second)

        // Verify consistency: LocalDateTime.parse should behave the same as Formats.ISO.parse
        val datetimeFromFormat = LocalDateTime.Formats.ISO.parse("+00000000000002022-07-16T12:30:45")
        assertEquals(datetime, datetimeFromFormat)

        // Also test negative years with leading zeroes
        val negativeDatetime = LocalDateTime.parse("-00000000000000001-01-01T00:00:00")
        assertEquals(-1, negativeDatetime.year)
        assertEquals(1, negativeDatetime.monthNumber)
        assertEquals(1, negativeDatetime.dayOfMonth)
    }
}
